package connectors.alfresco.connector.org.apache.manifoldcf.crawler.connectors.alfresco;

public class ContentModelUtils { public static boolean isDocument ( NamedValue [ ] properties ) { for ( NamedValue property : properties ) { if ( property . getName ( ) . equals ( Constants . PROP_CONTENT ) ) { return true ; } } return false ; } public static boolean isFolder ( String username , String password , AuthenticationDetails session , Reference node ) { QueryResult queryResult = null ; try { AuthenticationUtils . startSession ( username , password ) ; session = AuthenticationUtils . getAuthenticationDetails ( ) ; queryResult = WebServiceFactory . getRepositoryService ( ) . queryChildren ( node ) ; } catch ( RepositoryFault e ) { Logging . connectors . warn ( "Alfresco: Repository Error during the queryChildren: " + e . getMessage ( ) , e ) ; } catch ( RemoteException e ) { Logging . connectors . warn ( "Alfresco: Remote Error during the queryChildren: " + e . getMessage ( ) , e ) ; } finally { AuthenticationUtils . endSession ( ) ; session = null ; } if ( queryResult != null ) { ResultSet rs = queryResult . getResultSet ( ) ; if ( rs != null ) { ResultSetRow [ ] rows = rs . getRows ( ) ; if ( rows != null ) { if ( rows . length > 0 ) { return true ; } } } } return false ; } }